import React, { Component } from "react";
import Typical from "react-typical";
import Switch from "react-switch";
import { motion } from "framer-motion";

class Header extends Component {
  constructor() {
    super();
    this.state = { checked: false };
    this.onThemeSwitchChange = this.onThemeSwitchChange.bind(this);
  }

  componentDidMount() {
    const currentTheme = document.body.getAttribute("data-theme");
    this.setState({ checked: currentTheme === "dark" });
  }

  shouldComponentUpdate(nextProps, nextState) {
    return (
      nextState.checked !== this.state.checked ||
      nextProps.sharedData !== this.props.sharedData
    );
  }

  onThemeSwitchChange(checked) {
    this.setState({ checked });
    this.setTheme(checked);
  }

  setTheme(checked) {
    const dataThemeAttribute = "data-theme";
    const body = document.body;
    const newTheme = checked ? "dark" : "light";
    body.setAttribute(dataThemeAttribute, newTheme);
  }

  scrollToSection = (e, id) => {
    e.preventDefault();
    const element = document.getElementById(id);
    if (element) {
      element.scrollIntoView({
        behavior: "smooth",
        block: "start", 
      });
    }
  };

  render() {
    let name = "";
    let titles = [];
    let social = [];

    const navItems = [
      { id: "about", name: "About" },
      { id: "portfolio", name: "Projects" },
      { id: "skills", name: "Skills" },
      { id: "resume", name: "Experience" },
      { id: "contact", name: "Contact" }
    ];

    if (this.props.sharedData) {
      name = this.props.sharedData.name;
      titles = this.props.sharedData.titles.map(x => [x.toUpperCase(), 1500]).flat();
      social = this.props.sharedData.social || [];
    }

    const containerVariants = {
      hidden: { opacity: 0, y: 30 },
      visible: { 
        opacity: 1, 
        y: 0,
        transition: { duration: 0.8, ease: "easeOut", staggerChildren: 0.2 }
      }
    };

    const childVariants = {
      hidden: { opacity: 0, y: 20 },
      visible: { opacity: 1, y: 0 }
    };

    return (
      <header id="home" style={{ 
        height: '100vh', 
        minHeight: '600px',
        display: 'block',
        background: 'var(--body-background)',
        transition: 'background-color 0.6s ease',
        position: 'relative',
        overflow: 'hidden'
      }}>

        {/* THE WAVING GITHUB CORNER */}
        <a href="https://github.com" target="_blank" rel="noopener noreferrer" className="github-corner" aria-label="View source on GitHub">
          <svg width="90" height="90" viewBox="0 0 250 250" style={{ fill: '#AE944F', color: '#fff', position: 'absolute', top: 0, border: 0, right: 0, zIndex: 1001 }} aria-hidden="true">
            <path d="M0,0 L115,115 L130,115 L142,142 L250,250 L250,0 Z"></path>
            <path d="M128.3,109.0 C113.8,99.7 119.0,89.6 119.0,89.6 C122.0,82.7 120.5,78.6 120.5,78.6 C119.2,72.0 123.4,76.3 123.4,76.3 C127.3,80.9 125.5,87.3 125.5,87.3 C122.9,97.6 130.6,101.9 134.4,103.2" fill="currentColor" style={{ transformOrigin: '130px 106px' }} className="octo-arm"></path>
            <path d="M115.0,115.0 C114.9,115.1 118.7,116.5 119.8,115.4 L133.7,101.6 C136.9,99.2 139.9,98.4 142.2,98.6 C133.8,88.0 127.5,74.4 143.8,58.0 C148.5,53.3 154.0,51.2 159.7,51.0 C160.3,49.4 163.2,43.6 171.4,40.1 C171.4,40.1 176.1,42.5 178.8,56.2 C183.1,58.6 187.2,61.8 190.9,65.4 C194.5,69.0 197.7,73.2 200.1,77.6 C213.8,80.2 216.3,84.9 216.3,84.9 C212.7,93.1 206.9,96.0 205.4,96.6 C205.1,102.4 203.0,107.8 198.3,112.5 C181.9,128.9 168.3,122.5 157.7,114.1 C157.9,116.9 156.7,120.9 152.7,124.9 L141.0,136.5 C139.8,137.7 141.6,141.9 141.8,141.8 Z" fill="currentColor" className="octo-body"></path>
          </svg>
        </a>

        {/* Subtle Background Glow */}
        <motion.div 
          animate={{ scale: [1, 1.2, 1], opacity: [0.1, 0.2, 0.1] }}
          transition={{ duration: 8, repeat: Infinity, ease: "easeInOut" }}
          style={{
            position: "absolute", top: "20%", left: "10%", width: "400px", height: "400px",
            background: "radial-gradient(circle, #AE944F 0%, transparent 70%)",
            filter: "blur(80px)", zIndex: 0, pointerEvents: "none"
          }}
        />

        {/* SIDE SOCIAL QUICK LINKS */}
        <div style={{
          position: "absolute", left: "30px", top: "50%", transform: "translateY(-50%)",
          zIndex: 1000, display: "flex", flexDirection: "column", gap: "20px"
        }}>
          {social.map((network) => (
            <motion.a
              key={network.name}
              href={network.url}
              target="_blank"
              rel="noopener noreferrer"
              whileHover={{ scale: 1.3, color: "#AE944F" }}
              style={{ color: "var(--header-text)", fontSize: "22px", transition: "color 0.3s" }}
            >
              <i className={network.class}></i>
            </motion.a>
          ))}
          <div style={{ width: "2px", height: "60px", background: "#AE944F", margin: "0 auto", opacity: 0.5 }}></div>
        </div>

        {/* TOP NAV */}
        <nav style={{
          position: "absolute", top: "30px", right: "100px", // Adjusted right to not overlap corner
          zIndex: 1000, display: "flex", gap: "30px"
        }}>
          {navItems.map((item) => (
            <motion.button
              key={item.id}
              onClick={(e) => this.scrollToSection(e, item.id)}
              style={{
                background: "none", border: "none", cursor: "pointer",
                color: "var(--header-text)", fontSize: "1rem", fontWeight: "600",
                textTransform: "uppercase", letterSpacing: "1px",
              }}
              whileHover={{ scale: 1.1, color: "#AE944F" }}
              whileTap={{ scale: 0.95 }}
            >
              {item.name}
            </motion.button>
          ))}
        </nav>

        <div className="row aligner" style={{ height: '100%', margin: 0 }}>
          <motion.div 
            className="col-md-12"
            initial="hidden"
            animate="visible"
            variants={containerVariants}
            style={{ zIndex: 1 }}
          >
            <div>
              <motion.div
                animate={{ y: [0, -15, 0] }}
                transition={{ duration: 2, repeat: Infinity, ease: "easeInOut" }}
              >
                <span className="iconify header-icon" data-icon="la:laptop-code" style={{ color: 'var(--header-text)' }}></span>
              </motion.div>

              <br />

              <motion.h1 
                className="mb-0" 
                variants={childVariants}
                style={{ color: 'var(--header-text)', fontWeight: '700', fontSize: '4rem' }}
              >
                {name}
              </motion.h1>

              <motion.div className="title-container" variants={childVariants} style={{ height: '40px' }}>
                {titles.length > 0 && (
                  <Typical className="title-styles" steps={titles} loop={Infinity} />
                )}
              </motion.div>

              <motion.div 
                variants={childVariants} 
                style={{ 
                  marginTop: '40px', width: 'fit-content', margin: '40px auto 0 auto', 
                  borderRadius: '30px', padding: '6px', display: 'flex',
                  justifyContent: 'center', background: 'rgba(174,148,79, 0.1)',
                }} 
                whileHover={{ scale: 1.05, boxShadow: "0px 0px 20px rgba(174,148,79, 0.3)" }} 
                whileTap={{ scale: 0.95 }}
              >
                <Switch
                  checked={this.state.checked}
                  onChange={this.onThemeSwitchChange}
                  offColor="#baaa80"
                  onColor="#353535"
                  className="react-switch mx-auto"
                  width={90}
                  height={40}
                  uncheckedIcon={<span className="iconify" data-icon="twemoji:owl" style={{ display: "flex", alignItems: "center", justifyContent: "center", height: "100%", fontSize: 25, marginLeft: "15px" }}></span>}
                  checkedIcon={<span className="iconify" data-icon="noto-v1:sun-with-face" style={{ display: "flex", alignItems: "center", justifyContent: "center", height: "100%", fontSize: 25, marginLeft: "10px" }}></span>}
                  id="icon-switch"
                />
              </motion.div>
            </div>
          </motion.div>
        </div>

        {/* SCROLL DOWN INDICATOR */}
        <motion.div 
          initial={{ opacity: 0 }}
          animate={{ opacity: 1, y: [0, 10, 0] }}
          transition={{ delay: 2, duration: 2, repeat: Infinity }}
          style={{
            position: "absolute", bottom: "40px", left: "50%", transform: "translateX(-50%)",
            cursor: "pointer", color: "#AE944F", fontSize: "2.5rem", zIndex: 10
          }}
          onClick={(e) => this.scrollToSection(e, "about")}
        >
          <span className="iconify" data-icon="bi:chevron-double-down"></span>
        </motion.div>
      </header>
    );
  }
}

export default Header;
